1123	    /// # let t =
1124	    /// thread::spawn(move || {
1125	    ///     s.send(1).unwrap();
1126	    ///     thread::sleep(Duration::from_secs(1));
1127	    ///     s.send(2).unwrap();
1128	    ///     thread::sleep(Duration::from_secs(2));
1129	    ///     s.send(3).unwrap();
1130	    /// });
